if (!function_exists('theme_resolve_work_image_url')) {
    function theme_resolve_work_image_url($src) {
        if (empty($src)) {
            return '';
        }

        if (preg_match('/^https?:\/\//', $src) || strpos($src, '/') === 0) {
            return $src;
        }

        return get_template_directory_uri() . '/' . ltrim($src, '/');
    }
}

