<script>
(function () {
  /* ---- ローダー ---- */
  var loader = document.getElementById('archetLoader');
  var MIN_DISPLAY = 1800;
  var startTime = Date.now();
  function hideLoader() {
    var elapsed = Date.now() - startTime;
    var delay = Math.max(0, MIN_DISPLAY - elapsed);
    setTimeout(function () {
      loader.classList.add('is-hidden');
      loader.addEventListener('transitionend', function () {
        loader.remove();
      }, { once: true });
    }, delay);
  }
  if (document.readyState === 'complete') {
    hideLoader();
  } else {
    window.addEventListener('load', hideLoader, { once: true });
  }
})();

(function () {
  /* ---- ハンバーガーメニュー ---- */
  var burger      = document.getElementById('portfolio-burger');
  var sidebarClose = document.getElementById('portfolio-sidebar-close');
  var sidebar     = document.querySelector('.portfolio-sidebar');
  var overlay     = document.getElementById('portfolio-overlay');

  if (burger && sidebar && overlay) {
    function openMenu() {
      sidebar.classList.add('is-open');
      overlay.classList.add('is-open');
      burger.classList.add('is-open');
      burger.setAttribute('aria-expanded', 'true');
      document.body.style.overflow = 'hidden';
    }
    function closeMenu() {
      sidebar.classList.remove('is-open');
      overlay.classList.remove('is-open');
      burger.classList.remove('is-open');
      burger.setAttribute('aria-expanded', 'false');
      document.body.style.overflow = '';
    }
    burger.addEventListener('click', function () {
      sidebar.classList.contains('is-open') ? closeMenu() : openMenu();
    });
    if (sidebarClose) sidebarClose.addEventListener('click', closeMenu);
    overlay.addEventListener('click', closeMenu);
    sidebar.querySelectorAll('a').forEach(function (a) {
      a.addEventListener('click', closeMenu);
    });
  }
})();

(function () {
  /* ---- STEP 2: ripple ---- */
  var CYCLE2 = 3000, RD = 600;
  var ripples2 = [
    { el: document.getElementById('s2-rp1'), at: 0 },
    { el: document.getElementById('s2-rp2'), at: CYCLE2 * 0.50 },
    { el: document.getElementById('s2-rp3'), at: CYCLE2 * 0.82 }
  ];
  function tickRipple(ts) {
    var phase = ts % CYCLE2;
    ripples2.forEach(function(r) {
      var local = (phase - r.at + CYCLE2) % CYCLE2;
      if (local < RD) {
        var p = local / RD;
        r.el.setAttribute('r', p * 12);
        r.el.setAttribute('opacity', (1 - p) * 0.7);
      } else {
        r.el.setAttribute('r', 0);
        r.el.setAttribute('opacity', 0);
      }
    });
    requestAnimationFrame(tickRipple);
  }
  requestAnimationFrame(tickRipple);

  /* ---- STEP 3: code lines ---- */
  var CYCLE3 = 4000;
  var cls = ['s3-cl1','s3-cl2','s3-cl3','s3-cl4','s3-cl5','s3-cl6'].map(function(id){ return document.getElementById(id); });
  var cur3 = document.getElementById('s3-cur');
  var t3 = [0.05, 0.15, 0.25, 0.35, 0.45, 0.55];
  var SD = 0.12, HOLD = 0.82, FEND = 0.92;
  function eio(t) { return t < 0.5 ? 2*t*t : -1+(4-2*t)*t; }
  function tickCode(ts) {
    var p = (ts % CYCLE3) / CYCLE3;
    cls.forEach(function(el, i) {
      var t0 = t3[i], t1 = t0 + SD, op = 0;
      if (p >= t0 && p < t1)        op = eio((p - t0) / SD);
      else if (p >= t1 && p < HOLD) op = 1;
      else if (p >= HOLD && p < FEND) op = 1 - (p - HOLD) / (FEND - HOLD);
      el.style.opacity = op;
    });
    cur3.style.opacity = (p >= t3[5] + SD && p < FEND) ? 1 : 0;
    requestAnimationFrame(tickCode);
  }
  requestAnimationFrame(tickCode);

  /* ---- STEP 4: rocket ---- */
  var CYCLE4 = 3200;
  var rocket = document.getElementById('s4-rocket');
  var f1 = document.getElementById('s4-f1');
  var f2 = document.getElementById('s4-f2');
  function eIn3(t) { return t * t * t; }
  function tickRocket(ts) {
    var p = (ts % CYCLE4) / CYCLE4;
    var ty = 0, op = 1, fy = 1, fx = 1, wx = 0;
    if (p < 0.15) {
      wx = Math.sin(p * Math.PI * 12) * 1.2;
      fy = 1 + Math.abs(Math.sin(p * Math.PI * 10)) * 0.25;
      fx = 1 + Math.abs(Math.cos(p * Math.PI * 10)) * 0.1;
    } else if (p < 0.85) {
      var t = (p - 0.15) / 0.70;
      ty = -eIn3(t) * 200;
      fy = 1 + eIn3(t) * 1.8;
      fx = 1 + eIn3(t) * 0.5;
    } else {
      op = 1 - (p - 0.85) / 0.15;
      ty = -200;
    }
    rocket.setAttribute('transform', 'translate(' + wx + ',' + ty + ')');
    rocket.style.opacity = op;
    f1.setAttribute('ry', 20 * fy); f1.setAttribute('rx', 13 * fx);
    f2.setAttribute('ry', 13 * fy); f2.setAttribute('rx', 8  * fx);
    requestAnimationFrame(tickRocket);
  }
  requestAnimationFrame(tickRocket);
})();
</script>

